#!/usr/bin/env bash
# =============================================================================
# run_exp3.sh — Exp3: classification accuracy
#
# Evaluates the 5 sampling methods through remote Fuseki prob:jsdMode queries
# against reference JSD embedded in 4 difficulty-stratified datasets
# (easy / medium / hard / mixed), each with 2,400 aligned GMM pairs.
#
# Configuration (from Exp3Benchmark.java):
#   Ground truth      = prob:referenceJSD in remote datasets
#   Reference JSD     = 10^6-sample MC estimates generated by generate_exp3.py
#   WARMUP_REPEATS    = 3       (discarded warm-up repeats per method × pair)
#   MEASURED_REPEATS  = 10      (measured repeats per method × pair)
#
# Estimated runtime: 30–90 min
#
# Usage (from project root):
#   bash benchmark/scripts/Experiments3/run_exp3.sh
#
# Optional env vars:
#   OUTPUT_DIR   — override output directory
#   ENDPOINT_TEMPLATE — required, e.g. https://fujitsu:3030/{dataset}/query
#   SKIP_BUILD   — set to 1 to skip Maven compile
# =============================================================================
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "${SCRIPT_DIR}/../../.." && pwd)"

OUTPUT_DIR="${OUTPUT_DIR:-${PROJECT_ROOT}/benchmark/results/exp3}"
ENDPOINT_TEMPLATE="${ENDPOINT_TEMPLATE:-}"
SKIP_BUILD="${SKIP_BUILD:-0}"
EXPECTED_PAIRS="${EXPECTED_PAIRS:-2400}"
WARMUP_REPEATS="${WARMUP_REPEATS:-3}"
MEASURED_REPEATS="${MEASURED_REPEATS:-10}"

# ── Java 21 resolution ──────────────────────────────────────────────────────
if [[ -z "${JAVA_HOME:-}" ]]; then
    if command -v /usr/libexec/java_home &>/dev/null; then
        JAVA_HOME="$(/usr/libexec/java_home -v 21 2>/dev/null || /usr/libexec/java_home)"
    else
        JAVA_HOME="$(dirname "$(dirname "$(readlink -f "$(which java)")")")"
    fi
    export JAVA_HOME
fi
export PATH="$JAVA_HOME/bin:$PATH"
export JAVA_TOOL_OPTIONS="-Duser.language=en -Duser.country=US"

echo "=================================================================="
echo "  Experiment 3 — Classification Accuracy"
echo "=================================================================="
echo "  Project root : $PROJECT_ROOT"
echo "  Output dir   : $OUTPUT_DIR"
echo "  Endpoint tpl : ${ENDPOINT_TEMPLATE:-<required>}"
echo "  Java home    : $JAVA_HOME"
echo "  Expected N   : $EXPECTED_PAIRS aligned pairs per workload"
echo "  Warmup       : $WARMUP_REPEATS"
echo "  Runs         : $MEASURED_REPEATS"
echo "  Start time   : $(date)"
echo "------------------------------------------------------------------"
echo

cd "$PROJECT_ROOT"

if [[ -z "${ENDPOINT_TEMPLATE}" ]]; then
    echo "ERROR: ENDPOINT_TEMPLATE is required, e.g. https://fujitsu:3030/{dataset}/query" >&2
    exit 1
fi

# ── Step 1: Build ───────────────────────────────────────────────────────────
if [[ "${SKIP_BUILD}" != "1" ]]; then
    echo "[1/2] Building with Maven (skipping tests)..."
    mvn -q package -DskipTests
    echo "      Build complete."
else
    echo "[1/2] Build skipped (SKIP_BUILD=1)."
fi

mkdir -p "$OUTPUT_DIR"

# ── Step 2: Run benchmark ────────────────────────────────────────────────────
echo
echo "[2/2] Running Exp3Benchmark over remote endpoints..."
START_TS=$SECONDS


mvn -q exec:java \
    -Dexec.mainClass="org.apache.jena.probsparql.Exp3Benchmark" \
    "-Dexec.args=--endpoint-template ${ENDPOINT_TEMPLATE} \
                 --output-dir ${OUTPUT_DIR} \
                 --expected-pairs ${EXPECTED_PAIRS} \
                 --warmup ${WARMUP_REPEATS} \
                 --repeat ${MEASURED_REPEATS}" \
    2>&1 | tee "${OUTPUT_DIR}/exp3_run.log"

ELAPSED=$(( SECONDS - START_TS ))
echo
echo "------------------------------------------------------------------"
echo "  Exp 3 finished in ${ELAPSED}s  ($(date))"
echo "  Results:"
for F in exp3_classification.csv exp3_per_pair.csv; do
    if [[ -f "${OUTPUT_DIR}/${F}" ]]; then
        N=$(( $(wc -l < "${OUTPUT_DIR}/${F}") - 1 ))
        echo "    ${OUTPUT_DIR}/${F}  (${N} data rows)"
    fi
done
echo "=================================================================="
